fn dp_top_down(n: usize, cache: &mut Vec<Option<u32>>) -> Option<u32> {
    if n == 0 { Some(0) } else if n < 0 { return None }
    if let Some(&val) = cache.get(n).copied() { return val }

    let result = dp_top_down(n - 1, cache)
        .and_then(|v| v.checked_add(1))
        .and_then(|v| cache.get_mut(n).unwrap().insert(v));

    result
}
```

