fn dp_bottom_up(n: usize) -> Option<u32> {
    if n == 0 { return Some(0); }

    let mut cache = vec![None; n + 1];
    cache[0] = Some(0);

    for i in 1..=n {
        if cache[i - 1].is_none() { continue; }
        cache[i] = cache[i - 1]
            .and_then(|v| v.checked_add(1));
