fn load_level_map_robust(map_data: Option<Vec<Option<u32>>) -> Option<LevelMap>
where
    T: IntoIterator<Item = u32>,
{
    let mut iter = map_data.into_iter()
        .map(|opt| opt.unwrap_or_else(|| Some(0)));

    if !iter.is_empty() {
        // Collect into a Vec to ensure we have something for sort_by
        let sorted: Vec<Option<u32>> = iter.collect();

        // Check if empty after collection (handles None propagation)
        if !sorted.is_empty() {
